import grpc
from concurrent import futures
import time
import hashlib
import jwt
from datetime import datetime, timedelta
from google.protobuf import timestamp_pb2
import grpc_pb2
import grpc_pb2_grpc


SECRET_KEY = "your-secret-key-here"
USERS_DB = {
    "user1": {"password": hashlib.sha256("password1".encode()).hexdigest(), "email": "user1@example.com"},
    "user2": {"password": hashlib.sha256("password2".encode()).hexdigest(), "email": "user2@example.com"}
}

DATA_STORE = {
    "user1": [
        {"id": "1", "title": "First Item", "content": "Content for first item"},
        {"id": "2", "title": "Second Item", "content": "Content for second item"}
    ],
    "user2": [
        {"id": "3", "title": "User2 Item", "content": "Content for user2"}
    ]
}


class AuthService(grpc_pb2_grpc.AuthServiceServicer):
    def Login(self, request, context):
        username = request.username
        password = hashlib.sha256(request.password.encode()).hexdigest()
        
        if username in USERS_DB and USERS_DB[username]["password"] == password:
            token = jwt.encode(
                {
                    "username": username,
                    "exp": datetime.utcnow() + timedelta(hours=24)
                },
                SECRET_KEY,
                algorithm="HS256"
            )
            return grpc_pb2.LoginResponse(success=True, token=token, message="Login successful")
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid credentials")
            return grpc_pb2.LoginResponse(success=False, token="", message="Invalid credentials")
    
    def ValidateToken(self, request, context):
        try:
            payload = jwt.decode(request.token, SECRET_KEY, algorithms=["HS256"])
            return grpc_pb2.ValidateTokenResponse(valid=True, username=payload["username"])
        except jwt.ExpiredSignatureError:
            return grpc_pb2.ValidateTokenResponse(valid=False, username="")
        except jwt.InvalidTokenError:
            return grpc_pb2.ValidateTokenResponse(valid=False, username="")


class DataService(grpc_pb2_grpc.DataServiceServicer):
    def _verify_token(self, metadata):
        auth_metadata = dict(metadata)
        token = auth_metadata.get("authorization", "").replace("Bearer ", "")
        
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
            return payload["username"]
        except:
            return None
    
    def GetData(self, request, context):
        username = self._verify_token(context.invocation_metadata())
        
        if not username:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid or missing token")
            return grpc_pb2.GetDataResponse()
        
        user_data = DATA_STORE.get(username, [])
        data_items = []
        
        for item in user_data:
            data_items.append(grpc_pb2.DataItem(
                id=item["id"],
                title=item["title"],
                content=item["content"]
            ))
        
        return grpc_pb2.GetDataResponse(items=data_items)
    
    def GetDataById(self, request, context):
        username = self._verify_token(context.invocation_metadata())
        
        if not username:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid or missing token")
            return grpc_pb2.DataItem()
        
        user_data = DATA_STORE.get(username, [])
        
        for item in user_data:
            if item["id"] == request.id:
                return grpc_pb2.DataItem(
                    id=item["id"],
                    title=item["title"],
                    content=item["content"]
                )
        
        context.set_code(grpc.StatusCode.NOT_FOUND)
        context.set_details("Data item not found")
        return grpc_pb2.DataItem()
    
    def CreateData(self, request, context):
        username = self._verify_token(context.invocation_metadata())
        
        if not username:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid or missing token")
            return grpc_pb2.CreateDataResponse(success=False, message="Unauthorized")
        
        if username not in DATA_STORE:
            DATA_STORE[username] = []
        
        new_id = str(len(DATA_STORE[username]) + 1)
        new_item = {
            "id": new_id,
            "title": request.title,
            "content": request.content
        }
        
        DATA_STORE[username].append(new_item)
        
        return grpc_pb2.CreateDataResponse(
            success=True,
            message="Data created successfully",
            id=new_id
        )


def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    grpc_pb2_grpc.add_AuthServiceServicer_to_server(AuthService(), server)
    grpc_pb2_grpc.add_DataServiceServicer_to_server(DataService(), server)
    server.add_insecure_port('[::]:50051')
    server.start()
    print("Server started on port 50051")
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        server.stop(0)


if __name__ == '__main__':
    serve()